import { Pool } from "../../shared/db/connection";
import { Notification, CreateNotificationDto, NotificationStatus } from "./notification.model";

export interface INotificationRepository {
  create(dto: CreateNotificationDto): Promise<Notification>;
  findById(id: string): Promise<Notification | null>;
  findByRecipient(recipientId: string): Promise<Notification[]>;
  updateStatus(id: string, status: NotificationStatus): Promise<Notification>;
}

export class NotificationRepository implements INotificationRepository {
  constructor(private readonly pool: Pool) {}

  async create(dto: CreateNotificationDto): Promise<Notification> {
    const result = await this.pool.query(
      `INSERT INTO notifications (recipient_id, message, type)
       VALUES ($1, $2, $3)
       RETURNING id, recipient_id, message, type, status, read, created_at`,
      [dto.recipientId, dto.message, dto.type]
    );
    const row = result.rows[0];
    return {
      id: row.id,
      recipientId: row.recipient_id,
      message: row.message,
      type: row.type as NotificationType,
      status: row.status as NotificationStatus,
      read: row.read,
      createdAt: row.created_at,
    };
  }

  async findById(id: string): Promise<Notification | null> {
    const result = await this.pool.query(
      `SELECT id, recipient_id, message, type, status, read, created_at
       FROM notifications WHERE id = $1`,
      [id]
    );
    if (result.rows.length === 0) return null;
    const row = result.rows[0];
    return {
      id: row.id,
      recipientId: row.recipient_id,
      message: row.message,
      type: row.type as NotificationType,
      status: row.status as NotificationStatus,
      read: row.read,
      createdAt: row.created_at,
    };
  }

  async findByRecipient(recipientId: string): Promise<Notification[]> {
    const result = await this.pool.query(
      `SELECT id, recipient_id, message, type, status, read, created_at
       FROM notifications WHERE recipient_id = $1 ORDER BY created_at DESC`,
      [recipientId]
    );
    return result.rows.map(row => ({
      id: row.id,
      recipientId: row.recipient_id,
      message: row.message,
      type: row.type as NotificationType,
      status: row.status as NotificationStatus,
      read: row.read,
      createdAt: row.created_at,
    }));
  }

  async updateStatus(id: string, status: NotificationStatus): Promise<Notification> {
    const result = await this.pool.query(
      `UPDATE notifications
       SET status = $2,
           read = CASE WHEN $2 = 'read' THEN true ELSE read END
       WHERE id = $1
       RETURNING id, recipient_id, message, type, status, read, created_at`,
      [id, status]
    );
    const row = result.rows[0];
    return {
      id: row.id,
      recipientId: row.recipient_id,
      message: row.message,
      type: row.type as NotificationType,
      status: row.status as NotificationStatus,
      read: row.read,
      createdAt: row.created_at,
    };
  }
}","File: src/modules/audit/audit.model.ts
