export class AuditRepository implements IAuditRepository {
  constructor(private readonly pool: Pool) {}

  async create(dto: CreateAuditLogDto): Promise<AuditLog> {
    const result = await this.pool.query(
      `INSERT INTO audit_logs (entity_type, entity_id, action, old_value, new_value, changed_by)
       VALUES ($1, $2, $3, $4, $5, $6)
       RETURNING id, entity_type, entity_id, action, old_value, new_value, changed_by, changed_at`,
      [dto.entityType, dto.entityId, dto.action, dto.oldValue ?? null, dto.newValue ?? null, dto.changedBy ?? null]
    );
    const row = result.rows[0];
    return {
      id: row.id,
      entityType: row.entity_type,
      entityId: row.entity_id,
      action: row.action,
      oldValue: row.old_value,
      newValue: row.new_value,
      changedBy: row.changed_by,
      changedAt: row.changed_at,
    };
  }

  async findById(id: string): Promise<AuditLog | null> {
    const result = await this.pool.query(
      `SELECT id, entity_type, entity_id, action, old_value, new_value, changed_by, changed_at
       FROM audit_logs WHERE id = $1`,
      [id]
    );
    if (result.rows.length === 0) return null;
